   337|function resolveSendBranch(
   338|  deliveryBranch: DeliveryBranchStatus['branch'],
   339|  runtimeSource: RuntimeDebugSnapshot['source'],
   340|  httpStatus: string,
   341|): SendBranchProofRow {
   342|  if (deliveryBranch === 'not_observed') {
   343|    return { branch: null, label: 'pending', context: 'no send observed' };
   344|  }
   345|
   346|  const statusFragment = httpStatus !== 'pending' && httpStatus !== 'none' ? ` · ${httpStatus}` : '';
   347|
   348|  if (deliveryBranch === 'remote_db_insert') {
   349|    if (runtimeSource === 'remote_api' || runtimeSource === 'local_app_brain') {
   350|      return { branch: 'primary_realtime', label: 'primary_realtime', context: `assistant db insert${statusFragment}` };
   351|    }
   352|    if (runtimeSource === 'provider_fallback') {
   353|      return { branch: 'alternate_shared', label: 'alternate_shared', context: `gateway db insert${statusFragment}` };
   354|    }
   355|    return { branch: 'primary_realtime', label: 'primary_realtime', context: `db insert · source ${runtimeSource}${statusFragment}` };
   356|  }
   357|
   358|  if (deliveryBranch === 'local_fallback') {
   359|    return { branch: 'snapshot_fallback', label: 'snapshot_fallback', context: `local fallback path${statusFragment}` };
   360|  }
   361|
   362|  if (deliveryBranch === 'auth_session_failure') {
   363|    return { branch: 'local_only', label: 'local_only', context: `auth/session unavailable${statusFragment}` };
   364|  }
   365|
   366|  return { branch: 'local_only', label: 'local_only', context: `unresolved branch${statusFragment}` };
   367|}
